"use client";

import { Check, Clock } from "lucide-react";
import type { ComponentPropsWithoutRef } from "react";

import { cn } from "@/lib/utils";

import { createCompoundContext, statusClasses } from "../_lib/compound";
import type { TimelineStep } from "../_lib/compound";

const { Provider, useCompoundContext } =
  createCompoundContext<Record<string, never>>("OrderStatus");

export type OrderStatusProps = ComponentPropsWithoutRef<"div">;

interface TrackingNumberProps extends ComponentPropsWithoutRef<"div"> {
  value?: string;
}

function TrackingNumber({
  value = "1Z999AA10123456784",
  className,
  children,
  ...props
}: TrackingNumberProps) {
  useCompoundContext();
  return (
    <div className={cn("rounded-lg bg-muted/40 p-3", className)} {...props}>
      {children ?? (
        <>
          <p className="text-xs uppercase tracking-wide text-muted-foreground">
            Tracking number
          </p>
          <p className="font-mono text-sm">{value}</p>
        </>
      )}
    </div>
  );
}

interface StatusBadgeProps extends ComponentPropsWithoutRef<"span"> {
  status?: string;
}

function StatusBadge({
  status = "In transit",
  className,
  children,
  ...props
}: StatusBadgeProps) {
  useCompoundContext();
  return (
    <span
      className={cn(
        "inline-flex w-fit items-center rounded-full border px-2.5 py-1 text-xs font-medium",
        className
      )}
      {...props}
    >
      {children ?? status}
    </span>
  );
}

interface TimelineProps extends ComponentPropsWithoutRef<"ol"> {
  steps?: TimelineStep[];
}

function Timeline({
  steps = [],
  className,
  children,
  ...props
}: TimelineProps) {
  useCompoundContext();
  return (
    <ol className={cn("space-y-3 rounded-lg border p-4", className)} {...props}>
      {children ??
        steps.map((step) => (
          <li key={step.label} className="flex gap-3">
            <span className={statusClasses(step.status)}>
              {step.status === "completed" ? (
                <Check className="h-3.5 w-3.5" />
              ) : (
                <Clock className="h-3.5 w-3.5" />
              )}
            </span>
            <span>
              <span className="block text-sm font-medium">{step.label}</span>
              {step.description ? (
                <span className="block text-xs text-muted-foreground">
                  {step.description}
                </span>
              ) : null}
            </span>
          </li>
        ))}
    </ol>
  );
}

interface EstimatedDeliveryProps extends ComponentPropsWithoutRef<"p"> {
  value?: string;
}

function EstimatedDelivery({
  value = "Friday, January 20",
  className,
  children,
  ...props
}: EstimatedDeliveryProps) {
  useCompoundContext();
  return (
    <p className={cn("text-sm text-muted-foreground", className)} {...props}>
      {children ?? (
        <>
          Estimated delivery:{" "}
          <span className="font-medium text-foreground">{value}</span>
        </>
      )}
    </p>
  );
}

const defaultSteps: TimelineStep[] = [
  {
    description: "January 16 · 9:42 AM",
    label: "Order received",
    status: "completed",
  },
  {
    description: "January 17 · 3:18 PM",
    label: "Shipped",
    status: "completed",
  },
  {
    description: "Arrived at regional facility",
    label: "In transit",
    status: "current",
  },
  { label: "Delivered", status: "pending" },
];

function OrderStatusRoot({ className, children, ...props }: OrderStatusProps) {
  return (
    <Provider value={{}}>
      <div
        className={cn(
          "w-full space-y-4 rounded-xl border bg-card p-4 sm:p-6",
          className
        )}
        {...props}
      >
        {children ?? (
          <>
            <div className="flex items-center justify-between gap-3">
              <TrackingNumber />
              <StatusBadge />
            </div>
            <Timeline steps={defaultSteps} />
            <EstimatedDelivery />
          </>
        )}
      </div>
    </Provider>
  );
}

export const OrderStatus = Object.assign(OrderStatusRoot, {
  EstimatedDelivery,
  StatusBadge,
  Timeline,
  TrackingNumber,
});

"use client";

import { createContext, createElement, useContext } from "react";
import type { ReactNode } from "react";

import { cn } from "@/lib/utils";

export interface CompoundProviderProps<T> {
  children: ReactNode;
  value: T;
}

export const createCompoundContext = <T,>(name: string) => {
  const Context = createContext<T | null>(null);

  const Provider = ({ value, children }: CompoundProviderProps<T>) =>
    createElement(Context.Provider, { value }, children);

  const useCompoundContext = () => {
    const context = useContext(Context);

    if (!context) {
      throw new Error(`${name} subcomponents must be rendered inside ${name}.`);
    }

    return context;
  };

  return { Provider, useCompoundContext };
};

export const formatPrice = (value: number, currency = "USD") =>
  new Intl.NumberFormat("en-US", {
    currency,
    style: "currency",
  }).format(value);

export type StepStatus = "completed" | "current" | "pending";

export interface TimelineStep {
  description?: string;
  label: string;
  status?: StepStatus;
}

export const statusClasses = (status: StepStatus = "pending") =>
  cn(
    "flex h-6 w-6 items-center justify-center rounded-full text-xs",
    status === "completed" && "bg-foreground text-background",
    status === "current" && "border-2 border-foreground bg-card",
    status === "pending" && "border border-muted-foreground/40 bg-card"
  );

import type { TimelineStep } from "../_lib/compound";

export interface OrderItem {
  image?: string;
  name: string;
  price: number;
  quantity?: number;
  sku?: string;
  variant?: string;
}

export interface PaymentMethod {
  description?: string;
  label: string;
  value: string;
}

export interface RefundDetails {
  amount: number;
  steps: TimelineStep[];
}
